// URLs por competidor por categoría. Cada una se consulta a DataForSEO Labs
// (ranked_keywords) para obtener su tráfico orgánico estimado.

const URLS = [
  { competidor: 'Drean',           categoria: 'Lavado',         url: 'https://drean.com.ar/es_AR/Lavado/c/15' },
  { competidor: 'Drean',           categoria: 'Refrigeración', url: 'https://drean.com.ar/es_AR/Heladeras/c/9' },
  { competidor: 'Drean',           categoria: 'Cocinas',        url: 'https://drean.com.ar/es_AR/Cocci%C3%B3n/c/1' },
  { competidor: 'Electrolux',      categoria: 'Lavado',         url: 'https://www.tienda.electrolux.com.ar/grandes-electrodomesticos/lavarropas' },
  { competidor: 'Electrolux',      categoria: 'Refrigeración', url: 'https://www.tienda.electrolux.com.ar/grandes-electrodomesticos/heladeras' },
  { competidor: 'Electrolux',      categoria: 'Cocinas',        url: 'https://www.tienda.electrolux.com.ar/grandes-electrodomesticos/cocinas' },
  { competidor: 'Gafa',            categoria: 'Lavado',         url: 'https://www.tienda.gafa.com.ar/grandes-electrodomesticos/lavarropas' },
  { competidor: 'Gafa',            categoria: 'Refrigeración', url: 'https://www.tienda.gafa.com.ar/grandes-electrodomesticos/heladeras' },
  { competidor: 'Gafa',            categoria: 'Cocinas',        url: 'https://www.tienda.gafa.com.ar/grandes-electrodomesticos/cocinas' },
  { competidor: 'Whirlpool',       categoria: 'Lavado',         url: 'https://www.whirlpool.com.ar/electrodomesticos/lavarropas' },
  { competidor: 'Whirlpool',       categoria: 'Refrigeración', url: 'https://www.whirlpool.com.ar/electrodomesticos/heladeras' },
  { competidor: 'Whirlpool',       categoria: 'Cocinas',        url: 'https://www.whirlpool.com.ar/electrodomesticos/cocinas' },
  { competidor: 'Philco (Newsan)', categoria: 'Lavado',         url: 'https://tiendanewsan.com.ar/electrodomesticos/lavado/lavarropas.html' },
  { competidor: 'Philco (Newsan)', categoria: 'Refrigeración', url: 'https://tiendanewsan.com.ar/electrodomesticos/heladeras-freezers-y-cavas.html' },
];

const fecha = new Date().toISOString().slice(0, 10);
return URLS.map((u) => ({ json: { ...u, fecha } }));

// Para cada item (una URL consultada), sumamos los ETV de todos los
// keywords rankeados → tráfico orgánico estimado mensual hacia esa URL.
//
// Estructura de respuesta DataForSEO:
//   tasks[0].result[0].items[].keyword_data.keyword_info.search_volume
//   tasks[0].result[0].items[].ranked_serp_element.serp_item.etv
//   tasks[0].result[0].total_count

const output = [];

for (const item of $input.all()) {
  const meta = item.json;
  // El response de DataForSEO viene en distintos shapes según versión; tomamos defensivo
  const resp = item.json.body ?? item.json;
  const task = (resp.tasks && resp.tasks[0]) || resp;
  const result = (task.result && task.result[0]) || {};
  const items = result.items || [];
  const totalCount = result.total_count || items.length;

  let etvSum = 0;
  let keywordsCount = 0;
  for (const it of items) {
    const etv = it?.ranked_serp_element?.serp_item?.etv ?? it?.serp_item?.etv ?? 0;
    if (typeof etv === 'number') etvSum += etv;
    keywordsCount += 1;
  }

  output.push({
    json: {
      fecha: meta.fecha,
      competidor: meta.competidor,
      categoria: meta.categoria,
      url: meta.url,
      visitas_estimadas: Math.round(etvSum),
      raw: { total_count: totalCount, keywords_in_sample: keywordsCount, items_sample: items.slice(0, 5) },
      source: 'dataforseo_labs',
    },
  });
}

return output;
